"use strict";function t(t){return`${t.getFullYear()}-${String(t.getMonth()+1).padStart(2,"0")}-${String(t.getDate()).padStart(2,"0")}`}exports.dateToStr=t,exports.daysInMonth=function(t,e){return new Date(t,e,0).getDate()},exports.firstDayOfMonth=function(t,e){return new Date(t,e-1,1)},exports.formatDisplayDate=function(t){const e=new Date(t);return`${e.getFullYear()}年${e.getMonth()+1}月${e.getDate()}日 · 星期${["日","一","二","三","四","五","六"][e.getDay()]}`},exports.formatDuration=function(t){if(t<60)return`${t}秒`;const e=Math.floor(t/60),n=t%60;return n>0?`${e}分${n}秒`:`${e}分钟`},exports.isConsecutiveDay=function(t,e){const n=new Date(t),r=new Date(e);return n.setDate(n.getDate()+1),n.toDateString()===r.toDateString()},exports.today=function(){return t(new Date)};
